const webhookData = $('Webhook Evolution API').first().json;
const messageType = webhookData.body.data.messageType;

let userMessage = '';
let phoneNumber = webhookData.body.data.key.remoteJid.replace('@s.whatsapp.net', '');
let pushName = webhookData.body.data.pushName || 'Usuario';

if (messageType === 'conversation') {
  userMessage = webhookData.body.data.message.conversation;
} else if (messageType === 'extendedTextMessage') {
  userMessage = webhookData.body.data.message.extendedTextMessage.text;
} else if (messageType === 'audioMessage') {
  try {
    const whisperItems = $('Transcribir con Whisper').all();
    if (whisperItems && whisperItems.length > 0) {
      const whisperJson = whisperItems[0].json;
      userMessage = whisperJson.text || whisperJson.transcription || '[Audio sin transcripción]';
    } else {
      userMessage = '[No se pudo transcribir el audio]';
    }
  } catch (e) {
    userMessage = '[Error al transcribir audio: ' + e.message + ']';
  }
}

// Calcular calendario de referencia (2 semanas)
const dias = ['Domingo', 'Lunes', 'Martes', 'Miércoles', 'Jueves', 'Viernes', 'Sábado'];
const meses = ['enero', 'febrero', 'marzo', 'abril', 'mayo', 'junio', 'julio', 'agosto', 'septiembre', 'octubre', 'noviembre', 'diciembre'];

// Hoy en Paraguay (UTC-3 o UTC-4)
const ahora = new Date();
// Ajustar a Paraguay (UTC-3 standard, UTC-4 en invierno)
const paraguayOffset = -3; // PYT
const utc = ahora.getTime() + (ahora.getTimezoneOffset() * 60000);
const paraguayTime = new Date(utc + (3600000 * paraguayOffset));

const hoy = new Date(paraguayTime.getFullYear(), paraguayTime.getMonth(), paraguayTime.getDate());

let calendario = '';
for (let i = 0; i < 21; i++) {
  const d = new Date(hoy.getTime() + (i * 86400000));
  const diaSemana = dias[d.getDay()];
  const fecha = d.getDate();
  const mes = meses[d.getMonth()];
  const yyyy = d.getFullYear();
  const fechaISO = `${yyyy}-${String(d.getMonth()+1).padStart(2,'0')}-${String(fecha).padStart(2,'0')}`;
  const marca = i === 0 ? ' ← HOY' : '';
  calendario += `- ${diaSemana} ${fecha} de ${mes} ${yyyy} (${fechaISO})${marca}\n`;
}

const fechaHoy = `${dias[hoy.getDay()]} ${hoy.getDate()} de ${meses[hoy.getMonth()]} de ${hoy.getFullYear()}`;
const horaActual = `${String(paraguayTime.getHours()).padStart(2,'0')}:${String(paraguayTime.getMinutes()).padStart(2,'0')}`;


// Leer configuración del panel
let configPanel = {};
try {
  const configItems = $('Leer Config Panel').all();
  if (configItems && configItems.length > 0) {
    configPanel = configItems[0].json;
  }
} catch (e) {
  configPanel = {};
}

// Generar tabla de servicios desde la config
let tablaServicios = '';
const serviciosConfig = configPanel.servicios || [];
if (serviciosConfig.length > 0) {
  tablaServicios = '| Servicio | Duración | Precio |\n|----------|----------|--------|\n';
  serviciosConfig.forEach(s => {
    const precio = s.precio ? s.precio.toLocaleString('es-PY') + ' PYG' : 'Consultar';
    tablaServicios += '| ' + s.nombre + ' | ' + s.duracion + ' min | ' + precio + ' |\n';
  });
} else {
  tablaServicios = 'No hay servicios configurados aún.';
}

// Generar horarios legibles
let horariosTexto = '';
const horariosConfig = configPanel.horarios || {};
const diasOrden = ['lunes', 'martes', 'miercoles', 'jueves', 'viernes', 'sabado', 'domingo'];
const diasLabelConfig = { lunes: 'Lunes', martes: 'Martes', miercoles: 'Miércoles', jueves: 'Jueves', viernes: 'Viernes', sabado: 'Sábado', domingo: 'Domingo' };
diasOrden.forEach(d => {
  const h = horariosConfig[d];
  if (h) {
    horariosTexto += diasLabelConfig[d] + ': ' + (h.cerrado ? 'Cerrado' : h.abre + ' - ' + h.cierra) + '\n';
  }
});

return [{
  json: {
    chatInput: userMessage,
    sessionId: phoneNumber,
    phoneNumber: phoneNumber,
    pushName: pushName,
    instanceName: webhookData.body.instance,
    messageType: messageType,
    timestamp: new Date().toISOString(),
    fechaHoy: fechaHoy,
    horaActual: horaActual,
    calendario: calendario,
    configPanel: configPanel,
    tablaServicios: tablaServicios,
    horariosTexto: horariosTexto,
    nombreClinica: configPanel.nombre_clinica || 'Clínica Dental',
    nombreBot: configPanel.nombre_bot || 'Sofía',
    direccionClinica: configPanel.direccion || '',
    telefonoClinica: configPanel.telefono || '',
    emailClinica: configPanel.email || '',
    promptSistema: configPanel.prompt_sistema || '',
    mensajeBienvenida: configPanel.mensaje_bienvenida || '',
    clinicaId: configPanel.clinica_id || null
  }
}];

const inputData = $input.first().json;
const base64Raw = inputData.data?.base64 || inputData.base64 || '';
if (!base64Raw) throw new Error('Campo base64 no encontrado');
const base64Clean = base64Raw.includes(',') ? base64Raw.split(',')[1] : base64Raw;
const buffer = Buffer.from(base64Clean, 'base64');
const mimetype = inputData.data?.mimetype || inputData.mimetype || 'audio/ogg; codecs=opus';
const ext = mimetype.includes('mp4') ? 'mp4' : mimetype.includes('mpeg') ? 'mp3' : 'ogg';
const binaryData = await this.helpers.prepareBinaryData(buffer, 'audio.' + ext, mimetype);
return [{ json: inputData, binary: { data: binaryData } }];

const webhookData = $('Webhook Evolution API').first().json;
const phoneNumber = webhookData.body.data.key.remoteJid.replace('@s.whatsapp.net', '');
const instanceName = webhookData.body.instance;
return [{ json: { phoneNumber, instanceName, message: '¡Hola! 😊 Por el momento solo puedo leer mensajes de texto y audios. Si necesitas ayuda con una cita, por favor escríbeme un mensaje de texto. ¡Gracias!' } }];

const error = $input.all()[0].json;
return [{ json: { subject: '[ERROR] Clinica Dental - Recepcionista WhatsApp v4', message: 'Error en workflow:
Nodo: ' + (error.execution?.error?.node?.name || 'Desconocido') + '
Error: ' + (error.execution?.error?.message || JSON.stringify(error)) + '
Timestamp: ' + new Date().toISOString() + '
Execution ID: ' + (error.execution?.id || 'N/A') } }];

const instanceRaw = $('Webhook Evolution API').first().json.body.instance || '';
const instanceName = instanceRaw.replace(/[^a-zA-Z0-9_-]/g, '');
if (!instanceName) {
  throw new Error('Instance name invalido o vacio');
}
return [{ json: { instanceName } }];
